from flask import Flask, request
import psycopg2
app = Flask(__name__)

@app.route('/query', methods=['POST'])
def query():
    data = request.get_json()
    table = data['table']
    columns = ', '.join(data['columns']) if 'columns' in data else '*'
    where_clause = ''  # Initialize an empty string for the WHERE clause
    
    if 'filters' in data:
        filters = data['filters']
        conditions = []
        
        for key, value in filters.items():
            conditions.append(f"{key}='{value}'")  # Build condition dynamically
        
        where_clause = 'WHERE ' + ' AND '.join(conditions)  
    
    sql_query = f"SELECT {columns} FROM {table} {where_clause}"
    
    conn = psycopg2.connect(dbname='your_database', user='username', password='password', host='localhost')  # Add your details here
    cur = conn.cursor()  
    cur.execute(sql_query)

    result = cur.fetchall()
    
    return { "data" : str(result)}

if __name__ == '__main__':
    app.run(port=5000, debug=True)